  <text x="40" y="320" fill="#fca5a5" font-size="13" font-family="sans-serif">Por cuenta &#8594; 10:1, largo dominante</text>
  <rect x="370" y="294" width="310" height="42" rx="6" fill="#182234"/>
  <text x="390" y="320" fill="#93c5fd" font-size="13" font-family="sans-serif">Por capital &#8594; podría ser neto corto</text>
  <text x="350" y="378" fill="#e4e4e7" font-size="13" font-weight="600" text-anchor="middle" font-family="sans-serif">El desajuste no es un error: son dos respuestas a preguntas distintas</text>
</svg>
</div>
<div class="de">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Die Drei Kennzahlen Messen Unterschiedliche Einheiten</text>
  <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Gleicher Markt, andere Fragen</text>
  <rect x="20" y="72" width="310" height="180" rx="10" fill="#18181b" stroke="#f87171" stroke-width="1.5"/>
  <text x="40" y="100" fill="#f87171" font-size="14" font-weight="700" font-family="sans-serif">Zählt Menschen (Konten)</text>
  <text x="40" y="130" fill="#fafafa" font-size="15" font-weight="600" font-family="sans-serif">Long/Short-Ratio</text>
  <text x="40" y="152" fill="#a1a1aa" font-size="12.5" font-family="sans-serif">Global Account Ratio</text>
  <text x="40" y="182" fill="#e4e4e7" font-size="12.5" font-family="sans-serif">700-$-Konto = 7-Mio.-$-Konto</text>
  <text x="40" y="202" fill="#e4e4e7" font-size="12.5" font-family="sans-serif">Beide zählen als eine „Stimme"</text>
  <text x="40" y="230" fill="#71717a" font-size="12" font-family="sans-serif">&#8594; Stimmungs-Werkzeug</text>
  <rect x="370" y="72" width="310" height="180" rx="10" fill="#18181b" stroke="#60a5fa" stroke-width="1.5"/>
  <text x="390" y="100" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">Zählt Geld (Nominalwert)</text>
  <text x="390" y="130" fill="#fafafa" font-size="15" font-weight="600" font-family="sans-serif">Funding Rate · Open Interest</text>
  <text x="390" y="152" fill="#a1a1aa" font-size="12.5" font-family="sans-serif">Kapitalgewichtet</text>
  <text x="390" y="182" fill="#e4e4e7" font-size="12.5" font-family="sans-serif">Abgerechnet nach Größe</text>
  <text x="390" y="202" fill="#e4e4e7" font-size="12.5" font-family="sans-serif">mal Preis</text>
  <text x="390" y="230" fill="#71717a" font-size="12" font-family="sans-serif">&#8594; Liquidationsrisiko-Werkzeug</text>
  <text x="20" y="278" fill="#fafafa" font-size="13.5" font-weight="700" font-family="sans-serif">Bsp: 10 kleine Long-Konten vs. 1 großes Short-Konto</text>
  <rect x="20" y="294" width="310" height="42" rx="6" fill="#27191b"/>
  <text x="40" y="320" fill="#fca5a5" font-size="13" font-family="sans-serif">Nach Konto &#8594; 10:1, klar long</text>
